def media_flexivel(*valores):
    return sum(valores) / len(valores)

print(media_flexivel(10, 20, 30))       # 20.0
print(media_flexivel(8, 7, 9, 6))       # 7.5

def calcular_total(*repasses, taxa=0.0):
    bruto = sum(repasses)
    return bruto * (1 + taxa)

print(f"Sem taxa:  R$ {calcular_total(100, 200, 50):.2f}")          # 350.00
print(f"Com taxa:  R$ {calcular_total(100, 200, 50, taxa=0.1):.2f}") # 385.00
